<module id="freq_div">
    <description>Frequency divider for generating 50MHz, 10MHz, and 1MHz clocks from a 100MHz input clock.</description>
    <ports>
        <input id="CLK_in">Input clock signal.</input>
        <input id="RST">Reset signal.</input>
        <output id="CLK_50">Output clock signal with a frequency of CLK_in divided by 2.</output>
        <output id="CLK_10">Output clock signal with a frequency of CLK_in divided by 10.</output>
        <output id="CLK_1">Output clock signal with a frequency of CLK_in divided by 100.</output>
    </ports>
    <implementation>
        // Counter for CLK_50
        reg clk_50_reg;
        always @(posedge CLK_in or negedge RST) begin
            if (!RST) begin
                clk_50_reg <= 1'b0;
            end else begin
                clk_50_reg <= ~clk_50_reg;
            end
        end

        // Counter for CLK_10
        reg [2:0] cnt_10;
        reg clk_10_reg;
        always @(posedge CLK_in or negedge RST) begin
            if (!RST) begin
                cnt_10 <= 3'd0;
                clk_10_reg <= 1'b0;
            end else begin
                if (cnt_10 == 3'd4) begin
                    clk_10_reg <= ~clk_10_reg;
                    cnt_10 <= 3'd0;
                end else begin
                    cnt_10 <= cnt_10 + 1;
                end
            end
        end

        // Counter for CLK_1
        reg [5:0] cnt_100;
        reg clk_1_reg;
        always @(posedge CLK_in or negedge RST) begin
            if (!RST) begin
                cnt_100 <= 6'd0;
                clk_1_reg <= 1'b0;
            end else begin
                if (cnt_100 == 6'd49) begin
                    clk_1_reg <= ~clk_1_reg;
                    cnt_100 <= 6'd0;
                end else begin
                    cnt_100 <= cnt_100 + 1;
                end
            end
        end

        // Assign outputs
        assign CLK_50 = clk_50_reg;
        assign CLK_10 = clk_10_reg;
        assign CLK_1 = clk_1_reg;
    </implementation>
</module>
```
